public CSVPrinter(final Appendable out, final CSVFormat format) throws IOException {
    Assertions.notNull(out, "out");
    Assertions.notNull(format, "format");

    this.out = out;
    this.format = format;
    this.format.validate();
    if (!format.containsHeader() && !format.useHeaders()) {
        throw new IllegalArgumentException("Output Format must contain a Header");
    } else if (!format.usesFirstRowAsHeader()) {
        String[] headers = new String[format.getMapping().size()];
        int i = 0;
        for (CSVRecord.Field mapping : format.getMapping().values()) {
            headers[i++] = mapping.getName();
        }
        printRecord((Object[])headers);

    } 

}

